insert into PROJECT (PROJECT_ID, PROJECT_NAME, EQ_NO, CREATION_TIME, CREATED_BY, PROJECT_DESCRIPTION, MAIN_PROJ_ID, LOCATION_TYPE, FUTILE, COORDINATE, OPTION_ONE, OPTION_TWO, OPTION_THREE, IS_TRNSPRT_STN, IS_MNGMNT_STN, PROJECTFLAG) select unique ('1' || stage_code), stage_description, 'UL', SYSDATE, 1, stage_description, '1364111290870', '44', 1, 'UL', 'UL', 'UL', 'UL', 1, 1, 1 from OFOUK_UNITS;
insert into PROJECT (PROJECT_ID, PROJECT_NAME, EQ_NO, CREATION_TIME, CREATED_BY, PROJECT_DESCRIPTION, MAIN_PROJ_ID, LOCATION_TYPE, FUTILE, COORDINATE, OPTION_ONE, OPTION_TWO, OPTION_THREE, IS_TRNSPRT_STN, IS_MNGMNT_STN, PROJECTFLAG) select unique ('1' || TRIM(BUILDING_TYPE) || TRIM(BUILDING_CODE) || TRIM(UNIT_CODE)) pid, (P.PROJECT_NAME || ' ' || BUILDING_CODE || UNIT_CODE) nm, 'UL', SYSDATE, 1, 'UL', ('1' || STAGE_CODE), 'RES-UNIT', 1, 'UL', 'UL', 'UL', 'UL', 1, 1, 0 from OFOUK_UNITS c left join PROJECT p on ('1' || c.STAGE_CODE) = p.PROJECT_ID;
insert into CLIENT_PROJECTS select unique ('1' || FORM_NO), ('1' || CLIENT_CODE), ('1' || TRIM(BUILDING_TYPE) || TRIM(BUILDING_CODE) || TRIM(UNIT_CODE)), '1', SYSDATE, 'purche', ('1' || STAGE_CODE), 1000, 'سنه', 'نقدى', 'None', (P.PROJECT_NAME || ' ' || BUILDING_CODE || UNIT_CODE), p.PROJECT_NAME from OFOUK_UNITS c left join PROJECT p on ('1' || c.STAGE_CODE) = p.PROJECT_ID;
